+        expect(entity.has(Foo)).toBe(true);
+        expect(entity.get(Foo)?.value).toBe(2);
+        expect(world.query(Foo)).toHaveLength(0);
+
+        world.deferred.flush();
+        expect(world.query(Foo)).toEqual([entity]);
+        expect(entity.get(Foo)?.value).toBe(2);
+    });
+
+    it('flushes a query scope when updateEach exits', () => {
